import { Component } from '@angular/core';
import { ProductService } from '../product.service';
import { Product } from '../Model';

@Component({
  selector: 'products',
  templateUrl: './products.component.html',
  styleUrls: ['./products.component.css']
})
export class ProductsComponent{

  products: Product[];

  constructor(private productService: ProductService) {
    this.products = this.productService.getProducts();
  }

}

<table class="table table-bordered table-striped">
  <thead>
    <tr>
      <th>Id</th>
      <th>Name</th>
      <th>Price</th>
      <th></th>

    </tr>
  </thead>
  <tbody>
    <!-- burada isActive değerinin false olmasına göre tr tagına .bg-secondary clasını ekle yağıyoruz(ilgili satırların zeminlerinin gri olması gerekiyor) -->
    <tr *ngFor="let p of products" [class.bg-secondary]="p.isActive==false">
      <td>{{p.id}}</td>
      <td>{{p.name}}</td>
      <td>{{p.price}}</td>
      <td>
         <button class="btn btn-primary"> Edit</button>
         <button class="btn btn-danger"> Delete</button>
      </td>
    </tr>
  </tbody>
</table>
